values.content:
=You are an AI assistant for Plum Insurance escalation management. Analyze this message and return ONLY valid JSON:

{"summary": "2-3 line summary", "account_name": "company name or Unknown", "issue_type": "one of: Claim Delayed, Claim Rejected, Policy Issuance, Onboarding Issue, Health ID Missing, Portal/Tech Issue, Cashless Failure, Reimbursement Delay, Premium Discrepancy, Endorsement Pending, Renewal Issue, Service Complaint, Training Request, Account Data Error, Network Hospital Issue, TPA Coordination, Document Issue, Billing/Invoice Issue, Coverage Query, General Inquiry", "action_needed": "one of: Decision, Follow-up, Unblock, Acknowledgement, Investigation", "urgent": "yes or no", "sentiment": "angry, frustrated, neutral, or polite"}

Message:
{{ $json.raw_text }}

parameters.jsCode:
// Parse AI response and merge with original data
let ai;
try {
  const text = $input.first().json.message?.content || $input.first().json.choices?.[0]?.message?.content || '{}';
  ai = JSON.parse(text.replace(/```json?\n?/g, '').replace(/```/g, '').trim());
} catch(e) {
  ai = { summary: 'Could not parse', account_name: 'Unknown', issue_type: 'General Inquiry', action_needed: 'Follow-up', urgent: 'no', sentiment: 'neutral' };
}

const orig = $('Normalize Data').first().json;

// Delay detection
const t = (orig.raw_text || '').toLowerCase();
let delay = 0;
if (t.includes('weeks') || t.includes('month')) delay += 3;
else if (t.includes('days')) delay += 2;
if (t.includes('no response') || t.includes('multiple follow')) delay += 2;
if (t.includes('legal') || t.includes('irdai') || t.includes('social media')) delay += 3;
if (t.includes('not renew')) delay += 3;

// Account importance
const name = (ai.account_name || '').toLowerCase();
const ent = ['tata','wipro','infosys','reliance','mahindra','airtel','hcl','godrej','larsen','asian paints'];
const mid = ['zoho','freshworks','razorpay','policybazaar','lenskart','pharmeasy','swiggy','cred','meesho'];
let acc_type = 'SME', acc_score = 20;
for (const n of ent) { if (name.includes(n)) { acc_type='Enterprise'; acc_score=40; break; } }
if (acc_type==='SME') for (const n of mid) { if (name.includes(n)) { acc_type='Mid-Market'; acc_score=30; break; } }

// Priority scoring
let score = acc_score;
const uc = ['Cashless Failure','Claim Delayed','Health ID Missing','Claim Rejected','Renewal Issue'];
const hc = ['Reimbursement Delay','Policy Issuance','Onboarding Issue','TPA Coordination','Service Complaint'];
if (uc.includes(ai.issue_type)) score += 30;
else if (hc.includes(ai.issue_type)) score += 20;
else score += 10;
if (ai.urgent === 'yes') score += 10;
score += Math.min(delay, 10);
if (ai.sentiment === 'angry') score += 5;
if (orig.source === 'WhatsApp') score += 5;
else if (orig.source === 'Slack') score += 3;
score = Math.min(score, 100);
let priority = score >= 75 ? 'Critical' : score >= 55 ? 'High' : score >= 35 ? 'Medium' : 'Low';

// Owner assignment
const it = (ai.issue_type || '').toLowerCase();
let owner = 'Vaishnavi Bhat';
if (priority === 'Critical') owner = 'Avik Bhandari';
else if (it.includes('claim')) owner = 'Ipsita Sahu';
else if (it.includes('policy') || it.includes('endorsement') || it.includes('onboarding')) owner = 'Manashi Das';
else if (it.includes('cashless') || it.includes('tpa') || it.includes('hospital')) owner = 'Arun Saseedharan';
else if (it.includes('portal') || it.includes('tech') || it.includes('data')) owner = 'Prakrut Shah';
else if (it.includes('premium') || it.includes('billing')) owner = 'Rather Faisal';

return [{ json: {
  id: 'ESC-' + Date.now(),
  title: (ai.summary || 'New Escalation').substring(0, 80),
  summary: ai.summary,
  account_name: ai.account_name,
  account_size: acc_type,
  category: ai.issue_type,
  source: orig.source,
  priority,
  priority_score: score,
  status: 'Open',
  owner,
  action_needed: ai.action_needed,
  created_at: orig.timestamp,
  updated_at: orig.timestamp,
  sla_deadline: new Date(Date.now() + 48*3600000).toISOString(),
  sender_name: orig.sender_name,
  sender_email: orig.sender_email,
  raw_message: orig.raw_text
} }];
